/* Auto-généré — runtime pour export HTML autonome. Regénérer: node rebuild-mq-export-runtime.js */
window.MQ_EXPORT_RUNTIME = {"version":"2026-05-26","styleCss":"﻿/* style.css - Design commun à toutes les machines */\r\n\r\n* {\r\n    margin: 0;\r\n    padding: 0;\r\n    box-sizing: border-box;\r\n}\r\n\r\nbody {\r\n    font-family: Arial, sans-serif;\r\n    overflow: hidden;\r\n    background: #f0f0f0;\r\n}\r\n\r\n/* ========== INPUTS ========== */\r\n\r\n\r\n.input-wrapper input[type=\"text\"] {\r\n    display: block;\r\n    width: 100%;\r\n    height: 100%;\r\n    padding: 4px 6px;\r\n    font-size: 56px;\r\n    border: 1px solid #ccc;\r\n    border-radius: 3px;\r\n    pointer-events: auto;\r\n    backdrop-filter: blur(2px);\r\n    z-index: 100;\r\n    background-color: #e7e7e7;\r\n}\r\n\r\n.input-wrapper textarea {\r\n    display: block;\r\n    width: 100%;\r\n    height: 100%;\r\n    padding: 4px 6px;\r\n    font-size: 56px;\r\n    border: 1px solid #ccc;\r\n    border-radius: 3px;\r\n    pointer-events: auto;\r\n    backdrop-filter: blur(2px);\r\n    z-index: 100;\r\n    background-color: #e7e7e7;\r\n    resize: none;\r\n    /* Empêcher le redimensionnement manuel */\r\n    line-height: 1;\r\n    /* Demande utilisateur */\r\n    overflow: hidden;\r\n}\r\n\r\ninput:disabled,\r\ninput[readonly].disabled-style {\r\n    background-color: rgb(240, 240, 240);\r\n    cursor: not-allowed;\r\n    border: 1px solid #ddd;\r\n}\r\n\r\ninput::placeholder {\r\n    color: #d3d3d3;\r\n    opacity: 1;\r\n}\r\n\r\n/* Tooltips */\r\n/*\r\n.input-wrapper[data-tooltip]:hover::after,\r\n.hotspot[data-tooltip]:hover::after {\r\n    content: attr(data-tooltip);\r\n    position: absolute;\r\n    bottom: 100%;\r\n    left: 50%;\r\n    transform: translateX(-50%);\r\n    background: #333;\r\n    color: white;\r\n    padding: 6px 10px;\r\n    border-radius: 4px;\r\n    font-size: 50px;\r\n        white-space: nowrap;\r\n    z-index: 1000;\r\n    opacity: 0;\r\n    animation: fadeInOut 1s forwards;\r\n}\r\n*/\r\n/*\r\n.input-wrapper[data-tooltip]:hover::before,\r\n.hotspot[data-tooltip]:hover::before {\r\n    content: \"\";\r\n    position: absolute;\r\n    bottom: 100%;\r\n    left: 50%;\r\n    transform: translateX(-50%);\r\n    border-width: 5px;\r\n    border-style: solid;\r\n    border-color: transparent transparent #333 transparent;\r\n    opacity: 0;\r\n    animation: fadeInOut 1s forwards;\r\n    z-index: 1000;\r\n}\r\n*/\r\n\r\n@keyframes fadeInOut {\r\n    0% {\r\n        opacity: 0;\r\n    }\r\n\r\n    20% {\r\n        opacity: 1;\r\n    }\r\n\r\n    80% {\r\n        opacity: 1;\r\n    }\r\n\r\n    100% {\r\n        opacity: 0;\r\n    }\r\n}\r\n\r\n/* ========== CONTROLES ========== */\r\n.controls {\r\n    position: fixed;\r\n    top: 10px;\r\n    left: 10px;\r\n    z-index: 200;\r\n    background: rgba(255, 255, 255, 0.9);\r\n    padding: 8px 12px;\r\n    border-radius: 6px;\r\n    font-weight: bold;\r\n    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.2);\r\n}\r\n\r\n/* ========== CANVAS ========== */\r\n.canvas-container {\r\n    position: fixed;\r\n    top: 0;\r\n    left: 0;\r\n    width: 100vw;\r\n    height: 100vh;\r\n    overflow: hidden;\r\n    cursor: grab;\r\n}\r\n\r\n.canvas-container.grabbing {\r\n    cursor: grabbing;\r\n}\r\n\r\n.page-wrapper {\r\n    position: absolute;\r\n    top: 0;\r\n    left: 0;\r\n    transform-origin: 0 0;\r\n    transition: transform 0.1s ease;\r\n}\r\n\r\n.page-container {\r\n    position: relative;\r\n    display: inline-block;\r\n}\r\n\r\n.page-image {\r\n    display: block;\r\n    max-width: none;\r\n    user-select: none;\r\n    -webkit-user-drag: none;\r\n    user-drag: none;\r\n    pointer-events: none; /* laisser le pan passer au canvas (fond non déplaçable comme fichier) */\r\n}\r\n\r\n/* ========== DRAG & DROP ========== */\r\n.draggable {\r\n    width: 50px;\r\n    height: 50px;\r\n    cursor: grab;\r\n    border: 1px solid #656565;\r\n    border-radius: 5px;\r\n    transition: opacity 0.2s;\r\n    pointer-events: auto;\r\n}\r\n\r\n.draggable:hover:not(.used) {\r\n    border-color: #007bff;\r\n}\r\n\r\n.draggable.used {\r\n    opacity: 0.3 !important;\r\n    cursor: not-allowed;\r\n}\r\n\r\n/* Wrapper pour images PNG avec ombre portée et mix-blend-mode */\r\n.png-wrap {\r\n    display: inline-block;\r\n    filter: drop-shadow(0 6px 10px rgba(0, 0, 0, 0.35));\r\n    transition: transform 0.2s;\r\n    /* Pour l'animation de survol */\r\n}\r\n\r\n/* L'image à l'intérieur conserve le mix-blend-mode */\r\n.png-wrap .png,\r\n.png-wrap img {\r\n    display: block;\r\n    mix-blend-mode: multiply;\r\n}\r\n\r\n/* Application du hover sur le wrapper plutôt que l'image directe */\r\n.png-wrap:hover {\r\n    transform: scale(1.05);\r\n}\r\n\r\n#targets {\r\n    display: flex;\r\n    justify-content: center;\r\n    gap: 8px;\r\n    margin: 10px 0 4px;\r\n}\r\n\r\n.dropzone {\r\n    width: 50px;\r\n    height: 50px;\r\n    border: 2px dashed #999;\r\n    border-radius: 6px;\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    background: white;\r\n    pointer-events: auto;\r\n    transition: all 0.3s ease;\r\n}\r\n\r\n.dropzone.drag-over {\r\n    border-color: #007bff;\r\n    background: #eaf5ff;\r\n}\r\n\r\n/* ✅ Effet vert gaming pour bonne réponse */\r\n.dropzone.dropzone-correct {\r\n    border: 3px solid #4caf50 !important;\r\n    background: rgba(76, 175, 80, 0.15) !important;\r\n    box-shadow: 0 0 20px rgba(76, 175, 80, 0.6), inset 0 0 10px rgba(76, 175, 80, 0.2);\r\n}\r\n\r\n/* ❌ Effet rouge gaming pour mauvaise réponse */\r\n.dropzone.dropzone-wrong {\r\n    border: 3px solid #f44336 !important;\r\n    background: rgba(244, 67, 54, 0.15) !important;\r\n    box-shadow: 0 0 15px rgba(244, 67, 54, 0.5);\r\n}\r\n\r\n.dropzone img {\r\n    max-width: 100%;\r\n    max-height: 100%;\r\n    pointer-events: none;\r\n}\r\n\r\n#result {\r\n    min-height: 20px;\r\n    margin-top: 8px;\r\n    font-weight: bold;\r\n    text-align: center;\r\n}\r\n\r\n.success {\r\n    color: green;\r\n}\r\n\r\n.error {\r\n    color: red;\r\n}\r\n\r\n#score-malus-container,\r\n#score-malus-container2 {\r\n    display: flex;\r\n    justify-content: center;\r\n    gap: 12px;\r\n    margin-top: 8px;\r\n    font-weight: bold;\r\n    font-size: 12px;\r\n}\r\n\r\n#malus-display {\r\n    color: red;\r\n}\r\n\r\n.hidden {\r\n    display: none !important;\r\n}\r\n\r\n/* Feedback couleurs */\r\n.correct {\r\n    background-color: #d4edda !important;\r\n    border-color: #28a745 !important;\r\n}\r\n\r\n.incorrect {\r\n    background-color: #f8d7da !important;\r\n    border-color: #dc3545 !important;\r\n}\r\n\r\n.in-progress {\r\n    background-color: #fbcd88 !important;\r\n    border-color: #f59840 !important;\r\n}\r\n\r\n/* ========== JEUX ========== */\r\n.background-box {\r\n    position: absolute;\r\n    top: 1721px;\r\n    right: 2604px;\r\n    width: 2266px;\r\n    height: 1675px;\r\n    background: rgb(255, 255, 255);\r\n    border-radius: 15px;\r\n    z-index: 5;\r\n}\r\n\r\n.carre_marron {\r\n    background: #a48870;\r\n    padding-bottom: 5px;\r\n    border-radius: 15px;\r\n}\r\n\r\n.drag-game {\r\n    position: relative;\r\n    background: rgb(255, 255, 255);\r\n    border-radius: 15px;\r\n    font-size: 30px;\r\n    z-index: 10;\r\n    min-width: 220px;\r\n    box-shadow: 6px 9px 3px rgba(0, 0, 0, 0.2);\r\n    scale: 4.2;\r\n    width: 23%;\r\n}\r\n\r\n#drag-game-on-page {\r\n    top: 20%;\r\n    left: 39%;\r\n}\r\n\r\n#drag-game-on-page2 {\r\n    top: 60%;\r\n    left: 39%;\r\n}\r\n\r\n.drag-game h2 {\r\n    margin: 0 0 8px;\r\n    font-size: 16px;\r\n    font-weight: bold;\r\n    color: #ffffff;\r\n    text-align: center;\r\n}\r\n\r\n#source,\r\n#source2 {\r\n    display: flex;\r\n    flex-wrap: wrap;\r\n    gap: 6px;\r\n    margin: 8px 0;\r\n    justify-content: center;\r\n}\r\n\r\n/* ========== FEEDBACK MESSAGE ========== */\r\n#feedback-message {\r\n    text-align: center;\r\n    margin-top: 20px;\r\n    font-size: 1.5em;\r\n    color: #2e7d32;\r\n    padding: 20px;\r\n    background-color: #e8f5e9;\r\n    border-radius: 10px;\r\n    z-index: 1000;\r\n    position: fixed;\r\n    top: 50%;\r\n    left: 50%;\r\n    transform: translate(-50%, -50%);\r\n    display: none;\r\n}\r\n\r\n/* ========== SPECIFIQUES ========== */\r\n.definition input {\r\n    font-size: 40px !important;\r\n    text-transform: capitalize;\r\n    color: #333;\r\n    border: 2px solid #333;\r\n}\r\n\r\n.hotspot {\r\n    background: transparent;\r\n    cursor: pointer;\r\n    z-index: 8;\r\n    position: absolute;\r\n    pointer-events: none;\r\n}\r\n\r\n.hotspot-image {\r\n    opacity: 100%;\r\n    display: block;\r\n    top: 0;\r\n    left: 0;\r\n    width: 100%;\r\n    height: 100%;\r\n    z-index: 10;\r\n    mix-blend-mode: multiply;\r\n}\r\n\r\n.hotspot-path {\r\n    pointer-events: auto !important;\r\n    cursor: pointer;\r\n}\r\n\r\n/* Tooltip flottant SVG */\r\n#svg-tooltip {\r\n    display: none;\r\n    position: fixed;\r\n    background: #333;\r\n    color: white;\r\n    padding: 8px 12px;\r\n    border-radius: 6px;\r\n    font-size: 16px;\r\n    font-weight: bold;\r\n    z-index: 10000 !important;\r\n    /* Très haut pour passer par-dessus tout */\r\n    pointer-events: none;\r\n    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.3);\r\n    white-space: nowrap;\r\n}\r\n\r\nbutton:disabled {\r\n    opacity: 0.5;\r\n    cursor: not-allowed;\r\n}\r\n\r\n.pdf-buttons {\r\n    margin-top: 12px;\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 10px;\r\n}\r\n\r\n.pdf-buttons button {\r\n    padding: 12px 16px;\r\n    font-size: 14px;\r\n    width: 280px;\r\n    text-align: center;\r\n    border: 1px solid #ccc;\r\n    border-radius: 6px;\r\n    cursor: pointer;\r\n}\r\n\r\n#download-pdf {\r\n    background-color: #f8f8f8;\r\n    color: #888;\r\n    opacity: 0.6;\r\n    /* Gris et pâle quand désactivé */\r\n}\r\n\r\n#download-pdf:not(:disabled) {\r\n    background-color: #007bff;\r\n    color: white;\r\n    opacity: 1;\r\n    cursor: pointer;\r\n}\r\n\r\n#download-pdf:disabled {\r\n    cursor: not-allowed;\r\n}\r\n\r\n#download-pdf-prof {\r\n    background-color: #e9ecef;\r\n    color: #333;\r\n}\r\n\r\n/* Inputs au-dessus du SVG */\r\n.input-wrapper {\r\n    position: absolute;\r\n    z-index: 20;\r\n    /* > 7 du SVG */\r\n}\r\n\r\n.input-wrapper input[type=\"text\"] {\r\n    position: relative;\r\n    /* rend z-index effectif */\r\n    z-index: 30;\r\n    cursor: text;\r\n    /* évite l'héritage du grab */\r\n}\r\n\r\n/* Optionnel (si tu veux bétonner côté CSS) */\r\nsvg {\r\n    pointer-events: none;\r\n}\r\n\r\n.hotspot-path {\r\n    cursor: pointer;\r\n}\r\n\r\n/* Gestion de l'opacité des hotspots au survol */\r\n.hs-fill {\r\n    transition: fill-opacity 0.3s ease;\r\n}\r\n\r\n.hotspot-group:hover .hs-fill {\r\n    fill-opacity: var(--alpha-active, 0.35) !important;\r\n}\r\n\r\ninput[type=\"text\"] {\r\n    transition: background-color 0.3s ease;\r\n}\r\n\r\n/* Orange pendant la frappe */\r\ninput.in-progress {\r\n    background-color: #ff9800;\r\n    color: rgb(0, 0, 0);\r\n}\r\n\r\n/* Rouge si faux */\r\ninput.incorrect {\r\n    background-color: #f44336;\r\n    color: rgb(0, 0, 0);\r\n}\r\n\r\n/* Vert si juste */\r\ninput.correct {\r\n    background-color: #4caf50;\r\n    color: rgb(0, 0, 0);\r\n}\r\n\r\n/* --- GAMIFICATION : Effet \"Pop\" (Succès) --- */\r\n\r\n@keyframes successPulse {\r\n    0% {\r\n        transform: scale(1);\r\n        box-shadow: 0 0 0 rgba(76, 175, 80, 0);\r\n    }\r\n\r\n    50% {\r\n        transform: scale(1.05);\r\n        box-shadow: 0 0 15px rgba(76, 175, 80, 0.6);\r\n        border-color: #4caf50;\r\n    }\r\n\r\n    100% {\r\n        transform: scale(1);\r\n        box-shadow: 0 0 0 rgba(76, 175, 80, 0);\r\n    }\r\n}\r\n\r\n/* On applique l'effet sur les inputs ET les textareas */\r\n.input-wrapper input.correct,\r\n.input-wrapper textarea.correct {\r\n    animation: successPulse 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);\r\n    background-color: #c8e6c9 !important;\r\n    /* Vert pâle */\r\n    border-color: #2e7d32 !important;\r\n    /* Bordure verte */\r\n    color: #1b5e20 !important;\r\n    /* Texte vert foncé */\r\n    font-weight: bold;\r\n}\r\n\r\n/* ========== ZOOM MOBILE (fichiers générés) ========== */\r\n.mobile-zoom-bar {\r\n    position: fixed;\r\n    right: 12px;\r\n    bottom: max(12px, env(safe-area-inset-bottom, 0px));\r\n    z-index: 10001;\r\n    display: flex;\r\n    flex-direction: column;\r\n    gap: 8px;\r\n    pointer-events: auto;\r\n}\r\n\r\n.mobile-zoom-bar button {\r\n    width: 48px;\r\n    height: 48px;\r\n    border: 2px solid #333;\r\n    border-radius: 50%;\r\n    background: rgba(255, 255, 255, 0.95);\r\n    font-size: 22px;\r\n    font-weight: bold;\r\n    line-height: 1;\r\n    cursor: pointer;\r\n    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);\r\n    touch-action: manipulation;\r\n    -webkit-tap-highlight-color: transparent;\r\n}\r\n\r\n.mobile-zoom-bar button:active {\r\n    background: #e3f2fd;\r\n}\r\n\r\n@media (max-width: 900px) {\r\n    .controls {\r\n        top: auto;\r\n        bottom: max(72px, calc(12px + env(safe-area-inset-bottom, 0px)));\r\n        left: 8px;\r\n        right: 72px;\r\n        max-width: calc(100vw - 80px);\r\n        font-size: 13px;\r\n        padding: 6px 10px;\r\n    }\r\n\r\n    .controls .progress-track {\r\n        width: 90px;\r\n    }\r\n\r\n    .controls .pdf-buttons {\r\n        flex-wrap: wrap;\r\n    }\r\n\r\n    .controls .pdf-buttons button {\r\n        font-size: 12px;\r\n        padding: 6px 10px !important;\r\n    }\r\n\r\n    #btnFullscreen {\r\n        top: auto !important;\r\n        bottom: max(12px, env(safe-area-inset-bottom, 0px)) !important;\r\n        right: 72px !important;\r\n    }\r\n}\r\n\r\n@media (min-width: 901px) {\r\n    .mobile-zoom-bar {\r\n        bottom: 20px;\r\n    }\r\n}\r\n\r\n/* ========== MODE IFRAME (Moodle, activité Page) ========== */\r\nhtml[data-embed=\"1\"],\r\nhtml[data-embed=\"1\"] body {\r\n    width: 100%;\r\n    height: 100%;\r\n    margin: 0;\r\n    overflow: hidden;\r\n}\r\n\r\nhtml[data-embed=\"1\"] .canvas-container {\r\n    position: absolute;\r\n    top: 0;\r\n    left: 0;\r\n    width: 100%;\r\n    height: 100%;\r\n}\r\n\r\nhtml[data-embed=\"1\"] .controls {\r\n    position: absolute;\r\n    top: 8px;\r\n    left: 8px;\r\n    right: auto;\r\n    max-width: calc(100% - 16px);\r\n}\r\n\r\nhtml[data-embed=\"1\"] .mobile-zoom-bar {\r\n    position: absolute;\r\n}\r\n\r\nhtml[data-embed=\"1\"] #btnFullscreen {\r\n    position: absolute !important;\r\n    top: 8px !important;\r\n    right: 8px !important;\r\n}","scriptJs":"﻿/* script_fixed_v2.js - PAN + Hotspots + Inputs + DnD with score+malus\n   Key behaviors:\n   - PAN/ZOOM works but never blocks DnD, inputs, hotspots (PAN starts after a small movement threshold on background only)\n   - SVG hotspots (data-image/data-tooltip) light up the image referenced by data-image (e.g., sciure.png)\n   - Inputs (via .input-wrapper) also light up images (data-image) and show tooltip\n   - DnD restores score + malus display (malus = 0.5 per wrong drop)\n   - admin=true (or prof=true) enables PDF button\n*/\n\n(() => {\n  'use strict';\n\n  /** Moodle / iframe : évite position:fixed + 100vh qui cassent le visuel */\n  function applyEmbedMode() {\n    try {\n      const q = new URLSearchParams(window.location.search);\n      const forced = q.get('embed') === '1' || q.has('embed');\n      const inIframe = window.self !== window.top;\n      if (forced || inIframe) {\n        document.documentElement.setAttribute('data-embed', '1');\n      }\n    } catch (_) {\n      document.documentElement.setAttribute('data-embed', '1');\n    }\n  }\n  applyEmbedMode();\n\n  // -----------------------\n  // AUDIO ENGINE (Générateur de sons)\n  // -----------------------\n  const audioCtx = new (window.AudioContext || window.webkitAudioContext)();\n\n  function playSound(type) {\n    if (audioCtx.state === 'suspended') audioCtx.resume();\n    const osc = audioCtx.createOscillator();\n    const gain = audioCtx.createGain();\n    osc.connect(gain);\n    gain.connect(audioCtx.destination);\n    const now = audioCtx.currentTime;\n\n    if (type === 'success') {\n      osc.type = 'sine';\n      osc.frequency.setValueAtTime(600, now);\n      osc.frequency.exponentialRampToValueAtTime(1200, now + 0.1);\n      gain.gain.setValueAtTime(0.1, now);\n      gain.gain.exponentialRampToValueAtTime(0.001, now + 0.5);\n      osc.start(now);\n      osc.stop(now + 0.5);\n    }\n    else if (type === 'error') {\n      osc.type = 'sawtooth';\n      osc.frequency.setValueAtTime(150, now);\n      osc.frequency.linearRampToValueAtTime(100, now + 0.15);\n      gain.gain.setValueAtTime(0.1, now);\n      gain.gain.linearRampToValueAtTime(0.001, now + 0.15);\n      osc.start(now);\n      osc.stop(now + 0.15);\n    }\n  }\n\n  // -----------------------\n  // 2. MOTEUR VISUEL (CSS Injections)\n  // -----------------------\n  function injectGamificationStyles() {\n    if (document.getElementById('gamification-styles')) return;\n    const style = document.createElement('style');\n    style.id = 'gamification-styles';\n    style.innerHTML = `\n      @keyframes successPop { 0% { transform: scale(1); } 50% { transform: scale(1.1); box-shadow: 0 0 20px rgba(76, 175, 80, 0.5); border-color: #2e7d32; } 100% { transform: scale(1); } }\n      @keyframes shake { 0%, 100% { transform: translateX(0); } 20% { transform: translateX(-6px); } 40% { transform: translateX(6px); } 60% { transform: translateX(-4px); } 80% { transform: translateX(4px); } }\n      @keyframes floatUpFade { 0% { transform: translate(-50%, 0) scale(1); opacity: 1; } 100% { transform: translate(-50%, -50px) scale(1); opacity: 0; } }\n      .input-success-anim { animation: successPop 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275) !important; background-color: #c8e6c9 !important; color: #1b5e20 !important; border: 2px solid #2e7d32 !important; font-weight: bold !important; }\n      .shake { animation: shake 0.4s ease-in-out; border-color: #d32f2f !important; box-shadow: 0 0 8px rgba(211, 47, 47, 0.4); }\n      .input-error { background-color: #ffcdd2 !important; border: 2px solid #c62828 !important; }\n      .input-partial { background-color: #ffe0b2 !important; border: 2px solid #ef6c00 !important; }\n      .floating-feedback { position: fixed; pointer-events: none; z-index: 10000; font-weight: 900; font-size: 28px; color: #2e7d32; text-shadow: 1px 1px 0 #fff; animation: floatUpFade 0.8s ease-out forwards; }\n    `;\n    document.head.appendChild(style);\n  }\n\n  function showFloatingFeedback(boxElement) {\n    const rect = boxElement.getBoundingClientRect();\n    const el = document.createElement('div');\n    el.classList.add('floating-feedback');\n    el.textContent = \"+1 🌟\";\n    const x = rect.left + (rect.width / 2);\n    const y = rect.top;\n    el.style.left = x + 'px';\n    el.style.top = y + 'px';\n    document.body.appendChild(el);\n    setTimeout(() => el.remove(), 800);\n  }\n\n\n  // -----------------------\n  // Global scores\n  // -----------------------\n  window.game1Score = 0;\n  window.game2Score = 0;\n\n  let scoreTimeout = null;\n\n  /** HTTP ↔ HTTPS : aligne une URL absolue sur le protocole de la page Moodle parente */\n  function mqAlignUrlToMoodleProtocol(url) {\n    if (!url || typeof url !== 'string') return url;\n    let parentProto = window.location.protocol;\n    try {\n      if (window.parent && window.parent.location && window.parent.location.protocol) {\n        parentProto = window.parent.location.protocol;\n      }\n    } catch (_) { /* cross-origin */ }\n    if (!/^https?:\\/\\//i.test(url)) return url;\n    try {\n      const u = new URL(url, window.location.href);\n      if (parentProto === 'https:') u.protocol = 'https:';\n      else if (parentProto === 'http:') u.protocol = 'http:';\n      return u.href;\n    } catch (_) {\n      return url.replace(/^https:/i, 'http:').replace(/^http:/i, parentProto === 'https:' ? 'https:' : 'http:');\n    }\n  }\n\n  function envoyerScoreAMoodle(scoreFinal) {\n    let finalCourseId = 1; // ID du cours Moodle (très important pour le contexte)\n    let finalCmid = 1;     // ID du module\n\n    // 1. Essai de récupération propre depuis les paramètres de l'iframe locale\n    const urlParams = new URLSearchParams(window.location.search);\n    if (urlParams.has('courseid') || urlParams.has('id')) {\n      finalCourseId = urlParams.get('courseid') || urlParams.get('id');\n      finalCmid = urlParams.get('cmid') || urlParams.get('id');\n    } else {\n      // En cas d'iframe sans paramètre, on fouille dans le parent\n      try {\n        if (window.parent && window.parent.M && window.parent.M.cfg) {\n          // Moodle expose le courseId ! C'est ce qu'il nous faut pour l'event et l'API\n          if (window.parent.M.cfg.courseId) {\n            finalCourseId = window.parent.M.cfg.courseId;\n          }\n        }\n        // Et on prend l'ID de l'URL parent comme cmid\n        const parentUrlParams = new URLSearchParams(window.parent.location.search);\n        if (parentUrlParams.has('id')) {\n          finalCmid = parentUrlParams.get('id');\n        }\n      } catch (e) {\n        console.warn(\"Impossible d'accéder à window.parent (Cross-Origin ou non embarqué)\");\n      }\n    }\n\n    const nomExercice = document.title || \"Synthese\";\n\n    // Essayer de trouver l'URL racine et la sesskey (clé de session Moodle) de l'application parent\n    let wwwroot = '';\n    let sesskey = '';\n\n    try {\n      if (window.parent && window.parent.M && window.parent.M.cfg) {\n        wwwroot = window.parent.M.cfg.wwwroot;\n        sesskey = window.parent.M.cfg.sesskey;\n      }\n    } catch (e) {\n      console.warn(\"Impossible d'accéder à la config Moodle du parent.\");\n    }\n\n    if (wwwroot && sesskey) {\n      wwwroot = mqAlignUrlToMoodleProtocol(wwwroot);\n      // Option 1 : Moodle External API Web Service\n      const wsUrl = wwwroot + '/lib/ajax/service.php?sesskey=' + sesskey + '&info=local_suivisynthese_save_score';\n      const payload = [{\n        index: 0,\n        methodname: 'local_suivisynthese_save_score',\n        args: {\n          courseid: parseInt(finalCourseId, 10),\n          pagename: nomExercice,\n          score: parseFloat(scoreFinal)\n        }\n      }];\n\n      fetch(wsUrl, {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        credentials: 'include', // <-- IMPORTANT: envoie les cookies de session Moodle\n        body: JSON.stringify(payload)\n      })\n        .then(r => r.json())\n        .then(data => {\n          if (data[0] && !data[0].error) {\n            console.log(\"Victoire ! Moodle External API a sauvegardé en BDD le score :\", scoreFinal);\n          } else {\n            console.error(\"Erreur de Web Service Moodle. Réponse brute :\", data);\n          }\n        })\n        .catch(e => console.error(\"Erreur de connexion WS Moodle :\", e));\n\n    } else {\n      // Option 2 (Fallback) : L'ancien script PHP au cas où\n      // (ex. si on est à la racine de Moodle en accès direct non iframe)\n      const payload = {\n        courseid: parseInt(finalCourseId, 10),\n        pagename: nomExercice,\n        score: parseFloat(scoreFinal)\n      };\n\n      // Si l'URL actuelle ou du parent contient moodle_V4 (ex. hébergement réel)\n      // on tente de s'ajuster, sinon on tape relative\n      let scriptUrl = '/local/suivisynthese/ajax_score.php';\n      let moodleDir = '';\n\n      try {\n        const match = window.parent.location.pathname.match(/\\/(moodle[^/]+)/i);\n        if (match) moodleDir = '/' + match[1];\n      } catch (e) { }\n\n      if (!moodleDir) {\n        const match2 = window.location.pathname.match(/\\/(moodle[^/]+)/i);\n        if (match2) moodleDir = '/' + match2[1];\n      }\n\n      scriptUrl = moodleDir + '/local/suivisynthese/ajax_score.php';\n\n      fetch(scriptUrl, {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        credentials: 'include', // <-- IMPORTANT: envoie les cookies de session Moodle\n        body: JSON.stringify(payload)\n      })\n        .then(r => r.json())\n        .then(data => {\n          if (data.status === 'success') {\n            console.log(\"Victoire ! L'ancien script PHP a sauvegardé en BDD le score :\", scoreFinal);\n          } else {\n            console.error(\"Moodle signale une erreur depuis l'ancien script :\", data.message || data.error || data);\n          }\n        })\n        .catch(e => console.error(\"Erreur de connexion script Moodle :\", e));\n    }\n  }\n\n  function updateGlobalScore() {\n    const scoreDisplay = document.getElementById('score');\n    const totalDisplay = document.getElementById('total-score');\n\n    // Calcul du score\n    let totalPoints = 0;\n    totalPoints += window.game1Score || 0;\n    totalPoints += window.game2Score || 0;\n\n    const allInputs = document.querySelectorAll('input[type=\"text\"], textarea');\n    allInputs.forEach(input => {\n      // On compte comme bon si la classe 'correct' est présente (ajoutée par initTextInputs)\n      if (input.classList.contains('correct') || input.classList.contains('input-success-anim')) {\n        totalPoints += 1;\n      }\n    });\n\n    // Affichage texte\n    if (scoreDisplay) scoreDisplay.textContent = String(totalPoints);\n\n    // Calcul total pour la barre\n    let maxPoints = allInputs.length;\n    if (totalDisplay) {\n      // Si vous avez du DnD, ajoutez le maxDnD ici\n      const maxDnD = 9;\n      maxPoints += maxDnD;\n      totalDisplay.textContent = String(maxPoints);\n    }\n\n    // --- MISE À JOUR BARRE DE PROGRESSION (Nouveau) ---\n    const fill = document.getElementById('progress-fill');\n    if (fill && maxPoints > 0) {\n      const pct = Math.min(100, Math.round((totalPoints / maxPoints) * 100));\n      fill.style.width = `${pct}%`;\n\n      if (pct === 100) fill.style.background = '#00c853';\n      else fill.style.background = 'linear-gradient(90deg, #4caf50, #81c784)';\n    }\n\n    // --- BUTTON ENABLE/DISABLE LOGIC (Student Mode) ---\n    const btnPdf = document.getElementById('download-pdf');\n    if (btnPdf) {\n      const urlParams = new URLSearchParams(window.location.search);\n      const isAdmin = urlParams.has('admin') || urlParams.has('prof');\n\n      // Admin always has logic handled by enablePdfIfAdmin (runs once), \n      // but we must ensure we don't accidentally disable it here if score < 50%.\n      // Ideally, if isAdmin is true, we simply do nothing here.\n\n      if (!isAdmin) {\n        const threshold = maxPoints * 0.5; // 50%\n        if (totalPoints >= threshold) {\n          btnPdf.disabled = false;\n          btnPdf.removeAttribute('disabled');\n          btnPdf.style.opacity = '1';\n          btnPdf.style.cursor = 'pointer';\n          btnPdf.style.backgroundColor = '#007bff';\n        } else {\n          btnPdf.disabled = true;\n          btnPdf.style.opacity = '0.5';\n          btnPdf.style.cursor = 'default';\n          // Keep original color or set it if needed, but opacity handles the look.\n        }\n      }\n    }\n\n    // --- ENVOI MOODLE AVEC DEBOUNCE ANTI-SPAM ---\n    // On attend 1.5 secondes après la dernière modification du score pour envoyer\n    clearTimeout(scoreTimeout);\n    scoreTimeout = setTimeout(() => {\n      envoyerScoreAMoodle(totalPoints);\n    }, 1500);\n  }\n  function resetInputs() {\n    document.querySelectorAll('input[type=\"text\"]').forEach(input => {\n      input.value = '';\n      input.classList.remove('correct', 'incorrect', 'in-progress');\n    });\n  }\n\n  // -----------------------\n  // Utilities\n  // -----------------------\n  const qsa = (sel, root = document) => Array.from(root.querySelectorAll(sel));\n\n  function pickFirstImage(raw) {\n    return String(raw || '')\n      .split(',')\n      .map(s => s.trim().replace(/^'+|'+$/g, ''))\n      .filter(Boolean)[0] || '';\n  }\n\n  // Création du tooltip unique\n  function ensureTooltip() {\n    // DÉBOGAGE : Supprimer TOUS les tooltips existants pour repartir à zéro\n    const existingTooltips = document.querySelectorAll('#svg-tooltip');\n    existingTooltips.forEach((t, index) => {\n      console.warn(`⚠️ Tooltip trouvé #${index + 1}:`, t);\n      if (index > 0) t.remove(); // Garder seulement le premier\n    });\n\n    let tip = document.getElementById('svg-tooltip');\n    if (tip) {\n      console.log('✅ Tooltip existant réutilisé');\n      return tip;\n    }\n\n    tip = document.createElement('div');\n    tip.id = 'svg-tooltip';\n    tip.style.cssText = `position: fixed; z-index: 99999; display: none; background: rgba(0,0,0,0.85); color: #fff; padding: 6px 10px; border-radius: 6px; font-size: 14px; pointer-events: none; max-width: 420px; box-shadow: 0 6px 18px rgba(0,0,0,0.35);`;\n    document.body.appendChild(tip);\n    console.log('🆕 Nouveau tooltip créé');\n    return tip;\n  }\n\n  function getOverlayFor(el) {\n    const page = el && el.closest ? el.closest('.page-container') : null;\n    if (page && page.id === 'page-2-container') {\n      return document.getElementById('image-overlay2') || document.getElementById('image-overlay');\n    }\n    return document.getElementById('image-overlay') || document.getElementById('image-overlay2');\n  }\n\n  function showOverlayFrom(el) {\n    const overlay = getOverlayFor(el);\n    if (!overlay) return;\n\n    const img = pickFirstImage(el.getAttribute('data-image'));\n    if (!img) {\n      overlay.style.backgroundImage = 'none';\n      return;\n    }\n\n    // Light up the referenced PNG only\n    overlay.style.backgroundRepeat = 'no-repeat';\n    overlay.style.backgroundPosition = '0 0';\n    overlay.style.backgroundSize = '100% 100%';\n    overlay.style.opacity = '1';\n    overlay.style.backgroundImage = `url(\"${img}\")`;\n  }\n\n  function hideOverlayFrom(el) {\n    const overlay = getOverlayFor(el);\n    if (!overlay) return;\n    overlay.style.backgroundImage = 'none';\n  }\n\n  // --- TOOLTIP AVEC PROTECTION ANTI-DOUBLON ---\n  let currentTooltipTarget = null;\n\n  function showTooltipFor(el, x, y) {\n    // --- Durée du tooltip (en ms) --- Peut-être définie via le HTML (data-duration)\n    const defaultTooltipDelay = window.tooltipDelay || 3000;\n    // Protection anti-doublon : si c'est déjà cet élément, on ne fait rien\n    if (currentTooltipTarget === el) {\n      console.log('🔄 Tooltip déjà affiché pour cet élément, skip');\n      return;\n    }\n\n    const text = String(el.getAttribute('data-tooltip') || '').trim();\n    if (!text) return;\n\n    console.log('📌 showTooltipFor appelé:', { text, element: el.className || el.tagName });\n    currentTooltipTarget = el;\n    const tip = ensureTooltip();\n\n    // Récupération de la police (Font) depuis data-tip-font ou data-hint-font\n    const font = el.getAttribute('data-tip-font') || el.getAttribute('data-hint-font') || 'inherit';\n\n    tip.innerHTML = '';\n    tip.textContent = text;\n    tip.style.fontFamily = font; // Application de la police\n    tip.style.display = 'block';\n\n    // --- Auto-hide ---\n    const timeoutAttr = el.getAttribute('data-duration') || el.getAttribute('data-tooltip-timeout');\n    const delay = timeoutAttr ? parseInt(timeoutAttr, 10) : defaultTooltipDelay;\n\n    console.log('⏱️ Durée tooltip:', { timeoutAttr, delay, element: el.className });\n\n    clearTimeout(tip.hideTimeout);\n    tip.hideTimeout = setTimeout(() => {\n      tip.style.display = 'none';\n      currentTooltipTarget = null;\n    }, delay);\n\n\n\n\n    moveTooltip(x, y);\n  }\n\n  function moveTooltip(x, y) {\n    const tip = document.getElementById('svg-tooltip');\n    if (tip && tip.style.display === 'block') {\n      tip.style.left = (x + 15) + 'px';\n      tip.style.top = (y + 15) + 'px';\n    }\n  }\n\n  function hideTooltip(el) {\n    // On ne cache que si c'est l'élément actif qui le demande\n    if (currentTooltipTarget === el || el === null || el === undefined) {\n      const tip = document.getElementById('svg-tooltip');\n      if (tip) tip.style.display = 'none';\n      currentTooltipTarget = null;\n    }\n  }\n\n  //////////////////////////\n  //\n\n\n  // -----------------------\n  // INITIALISATION DES EVENTS (Hotspots + Inputs) - VERSION UNIQUE\n  // -----------------------\n  function initInteractionEvents() {\n    ensureTooltip();\n\n\n    // Évite le double tooltip : supprime les \"title\" HTML natifs\n    document.querySelectorAll('[title]').forEach(el => el.removeAttribute('title'));\n    // A. GESTION DES HOTSPOTS (SVG)\n    document.querySelectorAll('.hotspot-group').forEach(g => {\n      const fill = g.querySelector('.hs-fill');\n      const stroke = g.querySelector('.hs-stroke');\n      const dataRect = g.querySelector('rect');\n\n      const alphaIdle = dataRect ? (dataRect.dataset.alphaIdle || 0) : 0;\n      const alphaActive = dataRect ? (dataRect.dataset.alphaActive || 0.35) : 0.35;\n\n      // Helper to toggle group\n      const toggleGroup = (groupId, active) => {\n        if (!groupId) return;\n        const peers = document.querySelectorAll(`[data-group=\"${groupId}\"]`);\n        peers.forEach(p => {\n          if (p === g) return; // Skip self\n          // If it's a hotspot\n          if (p.classList.contains('hotspot-group')) {\n            const pFill = p.querySelector('.hs-fill');\n            const pStroke = p.querySelector('.hs-stroke');\n            if (pFill) pFill.style.fillOpacity = active ? (p.dataset.alphaActive || 0.35) : (p.dataset.alphaIdle || 0);\n            if (pStroke) pStroke.style.strokeOpacity = active ? (p.dataset.alphaActive || 0.35) : (p.dataset.alphaIdle || 0);\n          }\n          // If it's an input wrapper (optional visual feedback)\n          if (p.classList.contains('input-wrapper')) {\n            // p.style.boxShadow = active ? '0 0 8px #2196f3' : 'none'; \n          }\n        });\n      };\n\n      // Etat initial\n      if (fill) fill.style.fillOpacity = alphaIdle;\n      if (stroke) stroke.style.strokeOpacity = alphaIdle;\n\n      g.addEventListener('pointerenter', (e) => {\n        if (fill) fill.style.fillOpacity = alphaActive;\n        if (stroke) stroke.style.strokeOpacity = alphaActive;\n\n        // Group Logic\n        toggleGroup(g.dataset.group, true);\n\n        if (typeof showOverlayFrom === 'function') showOverlayFrom(g);\n        showTooltipFor(g, e.clientX, e.clientY);\n      });\n\n      g.addEventListener('pointermove', (e) => moveTooltip(e.clientX, e.clientY));\n\n      g.addEventListener('pointerleave', () => {\n        if (fill) fill.style.fillOpacity = alphaIdle;\n        if (stroke) stroke.style.strokeOpacity = alphaIdle;\n\n        // Group Logic off\n        toggleGroup(g.dataset.group, false);\n\n        if (typeof hideOverlayFrom === 'function') hideOverlayFrom(g);\n        hideTooltip(g);\n      });\n    });\n\n    // B. GESTION DES INPUTS (Wrapper)\n    document.querySelectorAll('.input-wrapper').forEach(w => {\n\n      const toggleGroup = (groupId, active) => {\n        if (!groupId) return;\n        const peers = document.querySelectorAll(`[data-group=\"${groupId}\"]`);\n        peers.forEach(p => {\n          if (p === w) return;\n          // Hotspots\n          if (p.classList.contains('hotspot-group')) {\n            const pFill = p.querySelector('.hs-fill');\n            const pStroke = p.querySelector('.hs-stroke');\n            // Use defaults if dataset missing (safe fallback)\n            const aActive = p.dataset.alphaActive || 0.35;\n            const aIdle = p.dataset.alphaIdle || 0;\n            if (pFill) pFill.style.fillOpacity = active ? aActive : aIdle;\n            if (pStroke) pStroke.style.strokeOpacity = active ? aActive : aIdle;\n          }\n        });\n      };\n\n      w.addEventListener('pointerenter', (e) => {\n        if (typeof showOverlayFrom === 'function') showOverlayFrom(w);\n        showTooltipFor(w, e.clientX, e.clientY);\n        toggleGroup(w.dataset.group, true);\n      });\n\n      w.addEventListener('pointermove', (e) => moveTooltip(e.clientX, e.clientY));\n\n      w.addEventListener('pointerleave', () => {\n        if (typeof hideOverlayFrom === 'function') hideOverlayFrom(w);\n        hideTooltip(w);\n        toggleGroup(w.dataset.group, false);\n      });\n    });\n\n    // C. GESTION DES DRAGGABLES (Images DnD)\n    document.querySelectorAll('.draggable').forEach(d => {\n      // Migration title -> data-tooltip si nécessaire (rétro-compatibilité)\n      if (d.title && !d.getAttribute('data-tooltip')) {\n        d.setAttribute('data-tooltip', d.title);\n        d.removeAttribute('title');\n      }\n\n      d.addEventListener('pointerenter', (e) => {\n        showTooltipFor(d, e.clientX, e.clientY);\n      });\n      d.addEventListener('pointermove', (e) => moveTooltip(e.clientX, e.clientY));\n      d.addEventListener('pointerleave', () => {\n        hideTooltip(d);\n      });\n    });\n  }\n\n  // -----------------------\n  // DnD with score + malus\n  // -----------------------\n  function initDragGame(gameContainer, goodIds, targetCount, scoreContainerId, gameId) {\n    if (!gameContainer) return;\n\n    const draggables = qsa('.draggable', gameContainer);\n    const dropzones = qsa('.dropzone', gameContainer);\n    const resultDiv = gameContainer.querySelector('#result');\n\n    const scoreMalusContainer =\n      gameContainer.querySelector('.score-malus-container') ||\n      gameContainer.querySelector('#' + scoreContainerId) ||\n      gameContainer;\n\n    const goodSet = new Set(goodIds);\n    const used = new Set();\n\n    let nbErreurs = 0;\n\n    function ensureScoreDiv() {\n      let scoreDiv = gameContainer.querySelector('.score-display');\n      if (!scoreDiv) {\n        scoreDiv = document.createElement('div');\n        scoreDiv.className = 'score-display';\n        scoreMalusContainer.appendChild(scoreDiv);\n      }\n      return scoreDiv;\n    }\n\n    function ensureMalusDiv() {\n      let malusDiv = gameContainer.querySelector('.malus-display');\n      if (!malusDiv) {\n        malusDiv = document.createElement('div');\n        malusDiv.className = 'malus-display';\n        scoreMalusContainer.appendChild(malusDiv);\n      }\n      return malusDiv;\n    }\n\n    function computeBonnesPresentes() {\n      let bonnes = 0;\n      dropzones.forEach(zone => {\n        const img = zone.querySelector('img');\n        if (img && goodSet.has(img.dataset.id)) bonnes++;\n      });\n      return bonnes;\n    }\n\n    function afficherScoreEtMalus() {\n      const bonnes = computeBonnesPresentes();\n\n      // Keep global scoring consistent with your previous behavior\n      window[gameId + 'Score'] = bonnes;\n      updateGlobalScore();\n\n      const scoreBrut = bonnes - nbErreurs * 0.5;\n      const scoreFinal = Math.max(0, scoreBrut);\n      const scoreArrondi = Math.round(scoreFinal * 10) / 10;\n      const malusTotal = nbErreurs * 0.5;\n\n      const scoreDiv = ensureScoreDiv();\n      scoreDiv.textContent = `Score : ${scoreArrondi} / ${targetCount}`;\n\n      const malusDiv = ensureMalusDiv();\n      if (nbErreurs === 0) {\n        malusDiv.style.display = 'none';\n      } else {\n        malusDiv.style.display = 'block';\n        malusDiv.style.color = 'red';\n        malusDiv.textContent = `Malus : -${malusTotal.toFixed(1)}`;\n      }\n    }\n\n    function verifierCombinaisonComplete() {\n      if (!resultDiv) return;\n\n      const ids = [];\n      dropzones.forEach(zone => {\n        const img = zone.querySelector('img');\n        if (img && img.dataset && img.dataset.id) ids.push(img.dataset.id);\n      });\n\n      if (ids.length !== targetCount) {\n        resultDiv.textContent = '';\n        resultDiv.className = '';\n        return;\n      }\n\n      const set = new Set(ids);\n      const isCorrect = set.size === targetCount && [...set].every(id => goodSet.has(id));\n      resultDiv.className = isCorrect ? 'success' : 'error';\n      resultDiv.textContent = isCorrect ? '✅ Correct !' : '❌ Incorrect.';\n    }\n\n    function reactivate(id) {\n      const orig = gameContainer.querySelector(`.draggable[data-id=\"${CSS.escape(id)}\"]`);\n      if (!orig) return;\n      orig.classList.remove('used');\n      orig.draggable = true;\n      used.delete(id);\n    }\n\n    // Draggables\n    draggables.forEach(img => {\n      img.addEventListener('dragstart', (e) => {\n        if (img.classList.contains('used')) {\n          e.preventDefault();\n          return;\n        }\n        e.dataTransfer.setData('text/plain', img.dataset.id);\n        e.dataTransfer.effectAllowed = 'move';\n\n        // Fix pour le décalage du drag causé par le scale(0.25)\n        // Créer une copie de l'image pour le drag ghost\n        const rect = img.getBoundingClientRect();\n        const dragImage = img.cloneNode(true);\n        dragImage.style.position = 'absolute';\n        dragImage.style.top = '-9999px';\n        dragImage.style.left = '-9999px';\n        dragImage.style.opacity = '1'; /* Opacité pleine pour bien voir, ou 0.8 selon goût */\n\n        // IMPORTANT : On force la taille du fantôme à la taille VISUELLE (réduite) de l'élément\n        dragImage.style.width = rect.width + 'px';\n        dragImage.style.height = rect.height + 'px';\n\n        document.body.appendChild(dragImage);\n\n        // Plus besoin de diviser par le scale puisque l'image fantôme a maintenant la \"vraie\" taille visuelle\n        const offsetX = e.clientX - rect.left;\n        const offsetY = e.clientY - rect.top;\n\n        e.dataTransfer.setDragImage(dragImage, offsetX, offsetY);\n\n        // Nettoyer l'image temporaire après le drag\n        setTimeout(() => {\n          if (dragImage.parentNode) {\n            dragImage.parentNode.removeChild(dragImage);\n          }\n        }, 0);\n\n        img.style.opacity = '0.6';\n      });\n\n      img.addEventListener('dragend', () => {\n        img.style.opacity = '1';\n      });\n    });\n\n    // Dropzones\n    dropzones.forEach(zone => {\n      zone.addEventListener('dragover', (e) => {\n        e.preventDefault(); // required to allow dropping\n        e.dataTransfer.dropEffect = 'move';\n        zone.classList.add('drag-over');\n      });\n\n      zone.addEventListener('dragleave', () => {\n        zone.classList.remove('drag-over');\n      });\n\n      zone.addEventListener('drop', (e) => {\n        e.preventDefault();\n        zone.classList.remove('drag-over');\n\n        const id = e.dataTransfer.getData('text/plain');\n        if (!id) return;\n        if (used.has(id)) return;\n\n        const orig = gameContainer.querySelector(`.draggable[data-id=\"${CSS.escape(id)}\"]`);\n        if (!orig) return;\n\n        // If zone already had an image, reactivate it\n        const already = zone.querySelector('img');\n        if (already && already.dataset && already.dataset.id) {\n          reactivate(already.dataset.id);\n        }\n\n        // Place clone\n        zone.innerHTML = '';\n        const clone = orig.cloneNode(true);\n        clone.classList.remove('draggable');\n        clone.draggable = false;\n        clone.style.cursor = 'pointer';\n        // IMPORTANT: dans la dropzone, jamais grisé\n        clone.classList.remove('used');\n        clone.style.opacity = '1';\n        /* On ne retire PAS le filter pour garder l'ombre portée (png-wrap) */\n        /* clone.style.filter = 'none'; */\n        /* clone.style.webkitFilter = 'none'; */\n\n        // Click to remove from zone\n        clone.addEventListener('click', () => {\n          reactivate(id);\n          zone.innerHTML = '';\n          // Retirer les effets visuels\n          zone.classList.remove('dropzone-correct', 'dropzone-wrong');\n          verifierCombinaisonComplete();\n          afficherScoreEtMalus();\n        });\n\n        zone.appendChild(clone);\n\n        // Mark original as used\n        used.add(id);\n        orig.classList.add('used');\n        orig.draggable = false;\n\n        // --- FEEDBACK VISUEL ET SONORE IMMÉDIAT ---\n        const isCorrect = goodSet.has(id);\n\n        // Retirer les anciennes classes\n        zone.classList.remove('dropzone-correct', 'dropzone-wrong');\n\n        if (isCorrect) {\n          // ✅ BONNE RÉPONSE - Effet vert gaming\n          zone.classList.add('dropzone-correct');\n          playSound('success');\n          showFloatingFeedback(zone);\n\n          // Animation de la zone\n          void zone.offsetWidth; // Force reflow\n          zone.style.animation = 'none';\n          setTimeout(() => {\n            zone.style.animation = 'successPulse 0.6s ease-out';\n          }, 10);\n\n        } else {\n          // ❌ MAUVAISE RÉPONSE - Effet rouge gaming\n          zone.classList.add('dropzone-wrong');\n          playSound('error');\n\n          // Animation shake\n          void zone.offsetWidth; // Force reflow\n          zone.style.animation = 'none';\n          setTimeout(() => {\n            zone.style.animation = 'shake 0.4s ease-in-out';\n          }, 10);\n\n          // Malus: wrong drop increments errors\n          nbErreurs++;\n        }\n\n        verifierCombinaisonComplete();\n        afficherScoreEtMalus();\n      });\n    });\n\n    afficherScoreEtMalus();\n  }\n\n  // -----------------------\n  // PAN/ZOOM (non-blocking) — pinch 2 doigts + barre mobile\n  // -----------------------\n  function initPanZoom() {\n    const canvasContainer = document.getElementById('canvas-container') || document.querySelector('.canvas-container');\n    const pageWrapper = document.getElementById('page-wrapper') || document.querySelector('.page-wrapper');\n\n    if (!canvasContainer || !pageWrapper) return;\n\n    canvasContainer.style.touchAction = 'none';\n    canvasContainer.style.userSelect = 'none';\n    pageWrapper.style.transformOrigin = '0 0';\n\n    let BASE_W = pageWrapper.scrollWidth || pageWrapper.offsetWidth;\n    let BASE_H = pageWrapper.scrollHeight || pageWrapper.offsetHeight;\n\n    let scale = 1;\n    let offsetX = 0;\n    let offsetY = 0;\n\n    const MIN_SCALE = 0.1;\n    const MAX_SCALE = 6;\n    const PAN_THRESHOLD = 6;\n    const CLAMP_MARGIN = 120;\n\n    const activePointers = new Map();\n    let panPointerId = null;\n    let pendingPan = false;\n    let isPanning = false;\n    let downX = 0, downY = 0;\n    let lastX = 0, lastY = 0;\n\n    let isPinching = false;\n    let pinchStartDist = 0;\n    let pinchStartScale = 1;\n    let pinchStartOffsetX = 0;\n    let pinchStartOffsetY = 0;\n    let pinchAnchorX = 0;\n    let pinchAnchorY = 0;\n\n    // Ne pas inclure [data-tooltip] / hotspots : sinon tout le schéma bloque le pan\n    const INTERACTIVE_SELECTOR = [\n      'input', 'textarea', 'button', 'select', 'a', 'label',\n      '.input-wrapper',\n      '.drag-game', '.draggable', '.dropzone',\n      '.pdf-buttons', '.controls', '.mobile-zoom-bar',\n      '#svg-tooltip', '#btnFullscreen'\n    ].join(',');\n\n    function isInteractiveTarget(t) {\n      return !!(t && t.closest && t.closest(INTERACTIVE_SELECTOR));\n    }\n\n    function getViewport() {\n      const w = canvasContainer.clientWidth || window.innerWidth;\n      const h = canvasContainer.clientHeight || window.innerHeight;\n      return { w, h };\n    }\n\n    function refreshBaseSize() {\n      BASE_W = pageWrapper.scrollWidth || pageWrapper.offsetWidth;\n      BASE_H = pageWrapper.scrollHeight || pageWrapper.offsetHeight;\n    }\n\n    function clampOffsets() {\n      const { w, h } = getViewport();\n      refreshBaseSize();\n      const contentW = BASE_W * scale;\n      const contentH = BASE_H * scale;\n      const minX = Math.min(0, w - contentW) - CLAMP_MARGIN;\n      const maxX = Math.max(0, w - contentW) + CLAMP_MARGIN;\n      const minY = Math.min(0, h - contentH) - CLAMP_MARGIN;\n      const maxY = Math.max(0, h - contentH) + CLAMP_MARGIN;\n      offsetX = Math.max(minX, Math.min(maxX, offsetX));\n      offsetY = Math.max(minY, Math.min(maxY, offsetY));\n    }\n\n    let raf = null;\n    function applyTransform() {\n      clampOffsets();\n      pageWrapper.style.transform = `translate(${offsetX}px, ${offsetY}px) scale(${scale})`;\n    }\n    function scheduleApply() {\n      if (raf) return;\n      raf = requestAnimationFrame(() => {\n        raf = null;\n        applyTransform();\n      });\n    }\n\n    function zoomAt(factor, anchorX, anchorY) {\n      const oldScale = scale;\n      scale = Math.max(MIN_SCALE, Math.min(scale * factor, MAX_SCALE));\n      offsetX = anchorX - (anchorX - offsetX) * (scale / oldScale);\n      offsetY = anchorY - (anchorY - offsetY) * (scale / oldScale);\n      scheduleApply();\n    }\n\n    function fit() {\n      const { w, h } = getViewport();\n      refreshBaseSize();\n      scale = Math.min(w / BASE_W, h / BASE_H) * 0.85;\n      const contentW = BASE_W * scale;\n      const contentH = BASE_H * scale;\n      offsetX = (w - contentW) / 2;\n      offsetY = (h - contentH) / 2;\n      canvasContainer.style.cursor = 'grab';\n      applyTransform();\n    }\n\n    function pointerDistance() {\n      const pts = [...activePointers.values()];\n      if (pts.length < 2) return 0;\n      return Math.hypot(pts[1].x - pts[0].x, pts[1].y - pts[0].y);\n    }\n\n    function pointerCenter() {\n      const pts = [...activePointers.values()];\n      if (!pts.length) return { x: 0, y: 0 };\n      const sum = pts.reduce((acc, p) => ({ x: acc.x + p.x, y: acc.y + p.y }), { x: 0, y: 0 });\n      return { x: sum.x / pts.length, y: sum.y / pts.length };\n    }\n\n    function beginPinch() {\n      const dist = pointerDistance();\n      if (dist < 8) return;\n      isPinching = true;\n      pendingPan = false;\n      isPanning = false;\n      panPointerId = null;\n      pinchStartDist = dist;\n      pinchStartScale = scale;\n      pinchStartOffsetX = offsetX;\n      pinchStartOffsetY = offsetY;\n      const rect = canvasContainer.getBoundingClientRect();\n      const center = pointerCenter();\n      pinchAnchorX = center.x - rect.left;\n      pinchAnchorY = center.y - rect.top;\n    }\n\n    function updatePinch() {\n      const dist = pointerDistance();\n      if (!isPinching || pinchStartDist < 8) return;\n      const ratio = dist / pinchStartDist;\n      const newScale = Math.max(MIN_SCALE, Math.min(pinchStartScale * ratio, MAX_SCALE));\n      const sRatio = newScale / pinchStartScale;\n      offsetX = pinchAnchorX - (pinchAnchorX - pinchStartOffsetX) * sRatio;\n      offsetY = pinchAnchorY - (pinchAnchorY - pinchStartOffsetY) * sRatio;\n      scale = newScale;\n      scheduleApply();\n    }\n\n    function endPinchIfNeeded() {\n      if (activePointers.size >= 2) return;\n      isPinching = false;\n      pinchStartDist = 0;\n    }\n\n    function endPan() {\n      if (panPointerId !== null) {\n        try { canvasContainer.releasePointerCapture(panPointerId); } catch { }\n      }\n      panPointerId = null;\n      pendingPan = false;\n      isPanning = false;\n      canvasContainer.style.cursor = 'grab';\n    }\n\n    fit();\n\n    // Recalcul après chargement des images (sinon BASE_W = 0 → pan/zoom cassés)\n    const pageImages = pageWrapper.querySelectorAll('.page-image');\n    let pendingImg = pageImages.length;\n    const refitWhenReady = () => {\n      if (--pendingImg <= 0) fit();\n    };\n    pageImages.forEach((img) => {\n      img.setAttribute('draggable', 'false');\n      img.addEventListener('dragstart', (e) => e.preventDefault());\n      if (img.complete) refitWhenReady();\n      else img.addEventListener('load', refitWhenReady, { once: true });\n    });\n    window.addEventListener('load', () => fit());\n\n    canvasContainer.addEventListener('pointerdown', (e) => {\n      if (e.button !== 0) return;\n      if (isInteractiveTarget(e.target)) return;\n\n      activePointers.set(e.pointerId, { x: e.clientX, y: e.clientY });\n      try { canvasContainer.setPointerCapture(e.pointerId); } catch { }\n\n      if (activePointers.size === 2) {\n        beginPinch();\n        e.preventDefault();\n        return;\n      }\n\n      if (activePointers.size > 2) return;\n\n      panPointerId = e.pointerId;\n      pendingPan = true;\n      isPanning = false;\n      downX = lastX = e.clientX;\n      downY = lastY = e.clientY;\n    }, { passive: false });\n\n    canvasContainer.addEventListener('pointermove', (e) => {\n      if (!activePointers.has(e.pointerId)) return;\n\n      activePointers.set(e.pointerId, { x: e.clientX, y: e.clientY });\n\n      if (activePointers.size >= 2) {\n        if (!isPinching) beginPinch();\n        e.preventDefault();\n        updatePinch();\n        return;\n      }\n\n      if (isPinching) return;\n      if (panPointerId === null || e.pointerId !== panPointerId) return;\n      if (!pendingPan && !isPanning) return;\n\n      const dist = Math.hypot(e.clientX - downX, e.clientY - downY);\n      if (!isPanning) {\n        if (dist < PAN_THRESHOLD) return;\n        isPanning = true;\n        pendingPan = false;\n        canvasContainer.style.cursor = 'grabbing';\n        e.preventDefault();\n      } else {\n        e.preventDefault();\n      }\n\n      offsetX += e.clientX - lastX;\n      offsetY += e.clientY - lastY;\n      lastX = e.clientX;\n      lastY = e.clientY;\n      scheduleApply();\n    }, { passive: false });\n\n    function onPointerEnd(e) {\n      activePointers.delete(e.pointerId);\n      try { canvasContainer.releasePointerCapture(e.pointerId); } catch { }\n\n      endPinchIfNeeded();\n\n      if (panPointerId === e.pointerId) endPan();\n      else if (panPointerId !== null && !activePointers.has(panPointerId)) endPan();\n    }\n\n    canvasContainer.addEventListener('pointerup', onPointerEnd);\n    canvasContainer.addEventListener('pointercancel', onPointerEnd);\n\n    canvasContainer.addEventListener('wheel', (e) => {\n      if (isInteractiveTarget(e.target)) return;\n      e.preventDefault();\n      const rect = canvasContainer.getBoundingClientRect();\n      zoomAt(e.deltaY > 0 ? 0.6 : 1.1, e.clientX - rect.left, e.clientY - rect.top);\n    }, { passive: false });\n\n    window.addEventListener('resize', () => scheduleApply());\n\n    // Barre zoom tactile (smartphone / tablette)\n    const zoomBar = document.createElement('div');\n    zoomBar.className = 'mobile-zoom-bar';\n    zoomBar.setAttribute('aria-label', 'Zoom');\n    zoomBar.innerHTML = `\n      <button type=\"button\" data-zoom=\"out\" title=\"Dézoomer\" aria-label=\"Dézoomer\">−</button>\n      <button type=\"button\" data-zoom=\"fit\" title=\"Ajuster à l'écran\" aria-label=\"Ajuster\">⊡</button>\n      <button type=\"button\" data-zoom=\"in\" title=\"Zoomer\" aria-label=\"Zoomer\">+</button>\n    `;\n    document.body.appendChild(zoomBar);\n\n    zoomBar.addEventListener('click', (e) => {\n      const btn = e.target.closest('button[data-zoom]');\n      if (!btn) return;\n      const { w, h } = getViewport();\n      const anchorX = w / 2;\n      const anchorY = h / 2;\n      if (btn.dataset.zoom === 'in') zoomAt(1.35, anchorX, anchorY);\n      else if (btn.dataset.zoom === 'out') zoomAt(1 / 1.35, anchorX, anchorY);\n      else fit();\n    });\n\n    window.__panZoomFit = fit;\n  }\n\n  // -----------------------\n  // PDF button enable\n  // -----------------------\n  function enablePdfIfAdmin() {\n    const btn = document.getElementById('download-pdf');\n    if (!btn) return;\n\n    const p = new URLSearchParams(window.location.search);\n    const isAdmin =\n      p.get('admin') === 'true' || p.has('admin') ||\n      p.get('prof') === 'true' || p.has('prof');\n\n    if (!isAdmin) return;\n\n    btn.disabled = false;\n    btn.removeAttribute('disabled');\n    btn.style.opacity = '1';\n    btn.style.cursor = 'pointer';\n    btn.style.backgroundColor = '#007bff';\n    btn.style.color = '#fff';\n  }\n\n  // -----------------------\n  // Inputs grading (GAMIFIED VERSION)\n  // -----------------------\n  function initTextInputs() {\n    injectGamificationStyles(); // On s'assure que le CSS est là\n    const inputs = document.querySelectorAll('input[type=\"text\"], textarea');\n\n    inputs.forEach(input => {\n      input.addEventListener('input', () => {\n        const answer = (input.getAttribute('data-answer') || '').toLowerCase().trim().replace(/\\s+/g, ' ');\n        const user = (input.value || '').toLowerCase().trim().replace(/\\s+/g, ' ');\n\n        // Reset des états\n        input.classList.remove('input-success-anim', 'shake', 'correct');\n        input.style.backgroundColor = '';\n\n        if (user === '') { updateGlobalScore(); return; }\n\n        if (user === answer) {\n          // --- SUCCÈS ---\n          void input.offsetWidth;\n          input.classList.add('input-success-anim');\n          input.classList.add('correct'); // Important pour le score global\n\n          showFloatingFeedback(input); // Le +1 qui vole\n          playSound('success');       // Le son Ding\n\n          input.readOnly = true;\n          input.style.pointerEvents = 'none';\n        }\n        else if (answer.startsWith(user)) {\n          // En cours de frappe correcte (optionnel, tu peux laisser vide)\n          input.style.backgroundColor = '#ffe0b2';\n        }\n        else {\n          // --- ERREUR ---\n          void input.offsetWidth;\n          input.classList.add('shake');\n          input.style.backgroundColor = '#ffcdd2';\n\n          // Anti-spam son erreur\n          if (!input.dataset.wasWrong) {\n            playSound('error');\n            input.dataset.wasWrong = \"true\";\n            setTimeout(() => input.dataset.wasWrong = \"\", 500);\n          }\n        }\n        updateGlobalScore();\n      });\n    });\n  }\n\n  // -----------------------\n  // Boot\n  // -----------------------\n  document.addEventListener('DOMContentLoaded', () => {\n    initInteractionEvents();  // Initialisation UNIQUE des tooltips\n    initTextInputs();\n    initPanZoom();\n    enablePdfIfAdmin();\n    updateGlobalScore();\n\n    // Initialisation Drag & Drop\n    document.querySelectorAll('.drag-game[data-dnd-good]').forEach(gameEl => {\n      const good = (gameEl.getAttribute('data-dnd-good') || '')\n        .split(',')\n        .map(s => s.trim())\n        .filter(Boolean);\n\n      const targetCount = parseInt(gameEl.getAttribute('data-dnd-target') || String(good.length), 10);\n      const scoreContainerId = gameEl.getAttribute('data-dnd-score-container') || '';\n      const gameId = gameEl.getAttribute('data-dnd-gameid') || gameEl.id || 'game';\n\n      if (typeof initDragGame === 'function') {\n        initDragGame(gameEl, good, targetCount, scoreContainerId, gameId);\n      }\n    });\n  });\n\n})();\n","pdfExportJs":"﻿// pdf-export.js - Version finale complète et corrigée\r\n\r\nclass PDFExporter {\r\n    constructor(options = {}) {\r\n        this.buttonId = options.buttonId || 'download-pdf';               // Bouton élève\r\n        this.profButtonId = options.profButtonId || 'download-pdf-prof';   // Bouton prof\r\n        this.backgroundImage1 = options.backgroundImage1 || 'images_cours/Dégauchisseuse 2020 P_Page_1.jpg';\r\n        this.backgroundImage2 = options.backgroundImage2 || 'images_cours/Dégauchisseuse 2020 P_Page_2.jpg';\r\n        this.annotationsSelector = options.annotationsSelector || '.input-wrapper, .hotspot, .hotspot-path, svg';\r\n        this.filenamePrefix = options.filenamePrefix || 'exercice';\r\n        this.userName = null;\r\n    }\r\n\r\n    init() {\r\n        const button = document.getElementById(this.buttonId);\r\n        const profButton = document.getElementById(this.profButtonId);\r\n\r\n        if (button) {\r\n            button.addEventListener('click', () => this.generatePDF({ anonymous: false }));\r\n        }\r\n        if (profButton) {\r\n            profButton.addEventListener('click', () => this.generatePDF({ anonymous: true }));\r\n        }\r\n    }\r\n\r\n    async getUserName() {\r\n        if (this.userName) return this.userName;\r\n\r\n        const selectors = ['.usermenu .usertext', '.usertext', '.login .usertext', '[data-region=\"usermenu\"] .usertext', '.navbar .usertext'];\r\n        for (const sel of selectors) {\r\n            const el = document.querySelector(sel);\r\n            if (el && el.textContent.trim()) {\r\n                this.userName = el.textContent.trim();\r\n                return this.userName;\r\n            }\r\n        }\r\n\r\n        const input = prompt('Entrez votre Prénom et Nom (ex: Jean Dupont) :');\r\n        this.userName = input?.trim() || 'Élève_Inconnu';\r\n        return this.userName;\r\n    }\r\n\r\n    parseName(fullName) {\r\n        const parts = fullName.trim().split(/\\s+/);\r\n        return {\r\n            firstname: parts[0] || 'Prénom',\r\n            lastname: parts.slice(1).join(' ') || 'Nom'\r\n        };\r\n    }\r\n\r\n    async ensureImageLoaded(imgEl) {\r\n        if (!imgEl) throw new Error('Image de page introuvable dans le HTML.');\r\n        if (imgEl.complete && imgEl.naturalWidth > 0) return imgEl;\r\n        return new Promise((resolve, reject) => {\r\n            imgEl.onload = () => {\r\n                if (imgEl.naturalWidth > 0) resolve(imgEl);\r\n                else reject(new Error('Image de synthèse invalide (dimensions nulles).'));\r\n            };\r\n            imgEl.onerror = () => reject(new Error(\r\n                'Image de synthèse non chargée. Régénérez le HTML avec ⚡ GÉNÉRER (images visibles dans l’éditeur).'\r\n            ));\r\n        });\r\n    }\r\n\r\n    /** Utilise l’<img class=\"page-image\"> déjà affichée (évite les chemins file:// locaux) */\r\n    async capturePageImage(...selectors) {\r\n        let el = null;\r\n        for (const sel of selectors) {\r\n            el = document.querySelector(sel);\r\n            if (el) break;\r\n        }\r\n        return this.ensureImageLoaded(el);\r\n    }\r\n\r\n    /** Convertit une Image (ou data URL) en chaîne utilisable par jsPDF */\r\n    imageToPdfData(img) {\r\n        if (typeof img === 'string' && img.startsWith('data:')) {\r\n            const m = img.match(/^data:image\\/(\\w+);/i);\r\n            const format = m && m[1].toLowerCase() === 'png' ? 'PNG' : 'JPEG';\r\n            return { data: img, format };\r\n        }\r\n        const w = img.naturalWidth || img.width;\r\n        const h = img.naturalHeight || img.height;\r\n        if (!w || !h) throw new Error('Image invalide pour le PDF.');\r\n        const canvas = document.createElement('canvas');\r\n        canvas.width = w;\r\n        canvas.height = h;\r\n        const ctx = canvas.getContext('2d');\r\n        ctx.drawImage(img, 0, 0);\r\n        let format = 'JPEG';\r\n        let data = canvas.toDataURL('image/jpeg', 0.92);\r\n        if (img.src && /^data:image\\/png/i.test(img.src)) {\r\n            format = 'PNG';\r\n            data = canvas.toDataURL('image/png');\r\n        }\r\n        return { data, format };\r\n    }\r\n\r\n    async loadLibraries() {\r\n        if (window.html2canvas && window.jspdf) return;\r\n\r\n        if (!window.html2canvas) {\r\n            await new Promise((resolve, reject) => {\r\n                const s = document.createElement('script');\r\n                s.src = 'https://html2canvas.hertzen.com/dist/html2canvas.min.js';\r\n                s.onload = resolve;\r\n                s.onerror = reject;\r\n                document.head.appendChild(s);\r\n            });\r\n        }\r\n\r\n        if (!window.jspdf) {\r\n            await new Promise((resolve, reject) => {\r\n                const s = document.createElement('script');\r\n                s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';\r\n                s.onload = resolve;\r\n                s.onerror = reject;\r\n                document.head.appendChild(s);\r\n            });\r\n        }\r\n    }\r\n\r\n    addFullPageImage(doc, img) {\r\n        const pdfWidth = doc.internal.pageSize.getWidth();   // 420 mm\r\n        const pdfHeight = doc.internal.pageSize.getHeight(); // 297 mm\r\n\r\n        const imgRatio = img.width / img.height;\r\n        const pageRatio = pdfWidth / pdfHeight;\r\n\r\n        let w, h, x = 0, y = 0;\r\n\r\n        if (imgRatio > pageRatio) {\r\n            h = pdfHeight;\r\n            w = h * imgRatio;\r\n            x = (pdfWidth - w) / 2;\r\n        } else {\r\n            w = pdfWidth;\r\n            h = w / imgRatio;\r\n            y = (pdfHeight - h) / 2;\r\n        }\r\n\r\n        const { data, format } = this.imageToPdfData(img);\r\n        doc.addImage(data, format, x, y, w, h);\r\n    }\r\n\r\n    async addAnnotationsOverlay(doc) {\r\n        const elements = document.querySelectorAll(this.annotationsSelector);\r\n        if (elements.length === 0) return;\r\n\r\n        const container = document.createElement('div');\r\n        container.style.position = 'absolute';\r\n        container.style.left = '-9999px';\r\n        container.style.background = 'transparent';\r\n\r\n        elements.forEach(el => container.appendChild(el.cloneNode(true)));\r\n\r\n        document.body.appendChild(container);\r\n\r\n        let canvas;\r\n        try {\r\n            canvas = await html2canvas(container, {\r\n                scale: 2,\r\n                backgroundColor: null,\r\n                useCORS: false,\r\n                allowTaint: true,\r\n                logging: false\r\n            });\r\n        } catch (err) {\r\n            console.warn('html2canvas annotations:', err);\r\n            document.body.removeChild(container);\r\n            return;\r\n        }\r\n\r\n        document.body.removeChild(container);\r\n\r\n        if (!canvas || canvas.width === 0 || canvas.height === 0) return;\r\n\r\n        const pdfWidth = doc.internal.pageSize.getWidth();\r\n        const pdfHeight = doc.internal.pageSize.getHeight();\r\n        const imgRatio = canvas.width / canvas.height;\r\n        const pageRatio = pdfWidth / pdfHeight;\r\n\r\n        let w, h, x = 0, y = 0;\r\n        if (imgRatio > pageRatio) {\r\n            h = pdfHeight;\r\n            w = h * imgRatio;\r\n            x = (pdfWidth - w) / 2;\r\n        } else {\r\n            w = pdfWidth;\r\n            h = w / imgRatio;\r\n            y = (pdfHeight - h) / 2;\r\n        }\r\n\r\n        doc.addImage(canvas.toDataURL('image/png'), 'PNG', x, y, w, h);\r\n    }\r\n\r\n    addHeaderText(doc, line1, line2, scoreText) {\r\n        doc.setFont('helvetica', 'normal');\r\n        doc.setTextColor(0, 0, 0);\r\n\r\n        doc.setFontSize(16);\r\n        const width1 = doc.getTextWidth(line1);\r\n        doc.text(line1, (210 - width1 - 10), 19);\r\n\r\n        doc.setFontSize(12);\r\n        const width2 = doc.getTextWidth(line2);\r\n        doc.text(line2, (210 - width2 - 10), 25);\r\n\r\n        doc.setFontSize(12);\r\n        const width3 = doc.getTextWidth(scoreText);\r\n        doc.text(scoreText, (210 - width3 - 10), 30);\r\n    }\r\n\r\n    async generatePDF(options = {}) {\r\n        const anonymous = options.anonymous || false;\r\n        // forceDownload is now handled by anonymous=true implicitly avoiding score check, \r\n        // or we can keep it if needed, but anonymous implies no score check.\r\n\r\n        const urlParams = new URLSearchParams(window.location.search);\r\n        const isAdmin = urlParams.has('admin') || urlParams.has('prof');\r\n\r\n        // CHECK SCORE ONLY IF NOT ANONYMOUS AND NOT ADMIN\r\n        if (!isAdmin && !anonymous) {\r\n            const scoreEl = document.getElementById('score');\r\n            const totalEl = document.getElementById('total-score');\r\n            const score = parseFloat(scoreEl?.textContent || 0);\r\n            const total = parseFloat(totalEl?.textContent || 10);\r\n\r\n            if (score < total / 2) {\r\n                alert(`Votre score (${score}/${total}) est insuffisant. Minimum requis : ${Math.ceil(total / 2)} points.`);\r\n                return;\r\n            }\r\n        }\r\n\r\n        await this.loadLibraries();\r\n\r\n        const { jsPDF } = window.jspdf;\r\n        const doc = new jsPDF({\r\n            orientation: 'landscape',\r\n            unit: 'mm',\r\n            format: 'a3'\r\n        });\r\n\r\n        let line1 = '';\r\n        let line2 = '';\r\n        let scoreText = '';\r\n        let firstname = 'Moi';\r\n        let lastname = 'Moi';\r\n\r\n        if (!anonymous) {\r\n            const fullName = await this.getUserName();\r\n            const names = this.parseName(fullName);\r\n            firstname = names.firstname;\r\n            lastname = names.lastname;\r\n            const today = new Date().toLocaleDateString('fr-FR');\r\n\r\n            const currentScore = document.getElementById('score')?.textContent.trim() || '0';\r\n            const totalScore = document.getElementById('total-score')?.textContent.trim() || '10';\r\n            scoreText = `Score : ${currentScore} / ${totalScore}`;\r\n\r\n            line1 = `${lastname.toUpperCase()} ${firstname}`;\r\n            line2 = `Date : ${today}`;\r\n        }\r\n\r\n        // PAGE 1\r\n        try {\r\n            const bgImg1 = await this.capturePageImage(\r\n                '#page-1-container .page-image',\r\n                '.page-container .page-image'\r\n            );\r\n            this.addFullPageImage(doc, bgImg1);\r\n        } catch (e) {\r\n            console.warn(e.message);\r\n            alert(`Erreur Page 1 : ${e.message}`);\r\n            doc.setFillColor(240, 240, 240);\r\n            doc.rect(0, 0, 420, 297, 'F');\r\n            doc.setFontSize(12);\r\n            doc.setTextColor(200, 0, 0);\r\n            doc.text('Image page 1 non disponible — régénérez le fichier HTML.', 10, 20);\r\n        }\r\n\r\n        try {\r\n            await this.addAnnotationsOverlay(doc);\r\n        } catch (err) {\r\n            console.warn('Annotations page 1:', err);\r\n        }\r\n        if (!anonymous) {\r\n            this.addHeaderText(doc, line1, line2, scoreText);\r\n        }\r\n\r\n        // PAGE 2\r\n        doc.addPage();\r\n\r\n        try {\r\n            const bgImg2 = await this.capturePageImage(\r\n                '#page-2-container .page-image',\r\n                '.page-container:nth-of-type(2) .page-image'\r\n            );\r\n            this.addFullPageImage(doc, bgImg2);\r\n        } catch (e) {\r\n            console.warn(e.message);\r\n            alert(`Erreur Page 2 : ${e.message}`);\r\n            doc.setFillColor(240, 240, 240);\r\n            doc.rect(0, 0, 420, 297, 'F');\r\n            doc.setFontSize(12);\r\n            doc.setTextColor(200, 0, 0);\r\n            doc.text('Image page 2 non disponible — régénérez le fichier HTML.', 10, 20);\r\n        }\r\n\r\n        if (!anonymous) {\r\n            this.addHeaderText(doc, line1, line2, scoreText);\r\n        }\r\n\r\n        // Téléchargement\r\n        const pdfBlob = doc.output('blob');\r\n        const url = URL.createObjectURL(pdfBlob);\r\n        const a = document.createElement('a');\r\n        a.href = url;\r\n        a.download = anonymous ? `${this.filenamePrefix}_synthese.pdf` : `${lastname}_${firstname}_${this.filenamePrefix}.pdf`;\r\n        a.style.display = 'none';\r\n        document.body.appendChild(a);\r\n        a.click();\r\n        setTimeout(() => {\r\n            document.body.removeChild(a);\r\n            URL.revokeObjectURL(url);\r\n        }, 100);\r\n    }\r\n}\r\n\r\ndocument.addEventListener('DOMContentLoaded', () => {\r\n    const d = document.body ? document.body.dataset : {};\r\n    const exporter = new PDFExporter({\r\n        filenamePrefix: d.pdfPrefix || 'exercice',\r\n    });\r\n    exporter.init();\r\n});\r\n","fullscreenJs":"﻿(function () {\r\n    document.addEventListener('DOMContentLoaded', () => {\r\n        // Injection des styles\r\n        const style = document.createElement('style');\r\n        style.textContent = `\r\n            #btnFullscreen {\r\n                position: fixed;\r\n                top: 20px;\r\n                right: 20px;\r\n                z-index: 10000;\r\n                background: rgba(255, 255, 255, 0.9);\r\n                border: 2px solid #333;\r\n                border-radius: 50%;\r\n                width: 50px;\r\n                height: 50px;\r\n                cursor: pointer;\r\n                box-shadow: 0 4px 6px rgba(0,0,0,0.3);\r\n                display: flex;\r\n                align-items: center;\r\n                justify-content: center;\r\n                font-size: 24px;\r\n                transition: all 0.3s ease;\r\n            }\r\n            #btnFullscreen:hover {\r\n                transform: scale(1.1);\r\n                background: #fff;\r\n            }\r\n        `;\r\n        document.head.appendChild(style);\r\n\r\n        // Création du bouton\r\n        const btn = document.createElement('button');\r\n        btn.id = 'btnFullscreen';\r\n        btn.title = 'Plein écran';\r\n        btn.innerHTML = '⛶'; // Icône plein écran\r\n        document.body.appendChild(btn);\r\n\r\n        // Logique de l'API\r\n        function toggleFullscreen() {\r\n            if (!document.fullscreenElement) {\r\n                document.documentElement.requestFullscreen().catch(err => {\r\n                    console.log(`Erreur lors de la tentative d'activation du mode plein écran : ${err.message} (${err.name})`);\r\n                });\r\n            } else {\r\n                if (document.exitFullscreen) {\r\n                    document.exitFullscreen();\r\n                }\r\n            }\r\n        }\r\n\r\n        function updateFullscreenButton() {\r\n            if (document.fullscreenElement) {\r\n                btn.innerHTML = '&#10006;'; // Icône de fermeture\r\n                btn.title = \"Quitter plein écran\";\r\n            } else {\r\n                btn.innerHTML = '&#9974;'; // Icône plein écran\r\n                btn.title = \"Plein écran\";\r\n            }\r\n        }\r\n\r\n        if (btn) {\r\n            btn.addEventListener('click', toggleFullscreen);\r\n            document.addEventListener('fullscreenchange', updateFullscreenButton);\r\n            // État initial\r\n            updateFullscreenButton();\r\n        }\r\n    });\r\n})();\r\n"};
